INSERT INTO BEST..TSEGMENTRULE ( SGTRUL_NT, SGMT_NF, SGT_NT, SGTVER_NT, RULE_LS, RULPRIO_CT, FUNCDEF_T, TECHDEF_T, CRE_D, CREUSR_CF, LSTUPD_D, LSTUPDUSR_CF, timestamp ) VALUES ( 1, 121, 1220, 1, 'MNP_SL', 89, ' not(RI_TYPE in (6,7,15,16,17,18)) AND UW_PFT_ORIGIN <> 255 AND SUBSIDIARY = 17 AND  CEDANT <> 31229 AND LOB <> ''15'' AND SEC_NATURE In (''41'',''40'') AND TTY_FAC_LIFE = ''T'' AND SEC_STATUS In (14,16,17,19) AND not(CLIENT_SCOR >=1) AND CTR_TRANSFERED <> true', '!((IntegerUtils.equals(c.getReitypCf(), 6) || IntegerUtils.equals(c.getReitypCf(), 7) || IntegerUtils.equals(c.getReitypCf(), 15) || IntegerUtils.equals(c.getReitypCf(), 16) || IntegerUtils.equals(c.getReitypCf(), 17) || IntegerUtils.equals(c.getReitypCf(), 18)))  && !IntegerUtils.equals(c.getUworgCf(), 255) && IntegerUtils.equals(c.getSsdCf(), 17) && !IntegerUtils.equals(c.getCedNf(), 31229) && !StringUtils.equals(c.getLobCf(), "15") && (StringUtils.equals(c.getNatCf(), "41") || StringUtils.equals(c.getNatCf(), "40")) && StringUtils.equals(c.getTflInd(), "T") && (IntegerUtils.equals(c.getSecstsCt(), 14) || IntegerUtils.equals(c.getSecstsCt(), 16) || IntegerUtils.equals(c.getSecstsCt(), 17) || IntegerUtils.equals(c.getSecstsCt(), 19)) && !(IntegerUtils.superiorOrEquals(c.getClissdCf(), 1))  && !BooleanUtils.equals(c.getTrftrtB(), true)', getDate(), 'DBEU', getDate(), 'MICM', null )
INSERT INTO BEST..TSEGMENTRULE ( SGTRUL_NT, SGMT_NF, SGT_NT, SGTVER_NT, RULE_LS, RULPRIO_CT, FUNCDEF_T, TECHDEF_T, CRE_D, CREUSR_CF, LSTUPD_D, LSTUPDUSR_CF, timestamp ) VALUES ( 1, 128, 1220, 1, 'MPSCred', 90, ' not(RI_TYPE in (7,6)) AND UW_PFT_ORIGIN <> 255 AND not(USER_CRITERIA_VALUE in (''09____Z'',''CONANOV'',''DEADREC'',''FARMERZ'',''GLOBREZ'',''NBS3L_Z'',''NOCODEZ'',''RS_DEVK'',''TOPSIDE'',''ZFS_QSZ'',''CBB___Z'',''GRPZ_S1'',''NBSCATZ'',''NBSRECZ'',''NBSZIBB'',''PCC___Z'',''REBATCH'',''NBS3A_Z'',''04CDCRZ'',''04CDMOZ'',''04C_MIS'')) AND SUBSIDIARY = 17 AND SEC_NATURE in (''10'',''11'',''12'',''20'',''21'',''22'',''23'') AND TTY_FAC_LIFE = ''T'' AND SEC_STATUS in (14,16,17,19) AND not(CEDANT in (11508,11550,11564,11721,11761,12365,12492,12726,12748)) AND not(SEC_ACCOUNTYPE in (1,4)) AND ((LOB = ''05'' AND TOP in (''130'',''131'',''137'',''138'',''170'',''190'',''195'') ) ) AND not(CLIENT_SCOR >= 1) AND CTR_TRANSFERED <> true', '!((IntegerUtils.equals(c.getReitypCf(), 7) || IntegerUtils.equals(c.getReitypCf(), 6)))  && !IntegerUtils.equals(c.getUworgCf(), 255) && !((StringUtils.equals(c.getUsrcrtvalLm(), "09____Z") || StringUtils.equals(c.getUsrcrtvalLm(), "CONANOV") || StringUtils.equals(c.getUsrcrtvalLm(), "DEADREC") || StringUtils.equals(c.getUsrcrtvalLm(), "FARMERZ") || StringUtils.equals(c.getUsrcrtvalLm(), "GLOBREZ") || StringUtils.equals(c.getUsrcrtvalLm(), "NBS3L_Z") || StringUtils.equals(c.getUsrcrtvalLm(), "NOCODEZ") || StringUtils.equals(c.getUsrcrtvalLm(), "RS_DEVK") || StringUtils.equals(c.getUsrcrtvalLm(), "TOPSIDE") || StringUtils.equals(c.getUsrcrtvalLm(), "ZFS_QSZ") || StringUtils.equals(c.getUsrcrtvalLm(), "CBB___Z") || StringUtils.equals(c.getUsrcrtvalLm(), "GRPZ_S1") || StringUtils.equals(c.getUsrcrtvalLm(), "NBSCATZ") || StringUtils.equals(c.getUsrcrtvalLm(), "NBSRECZ") || StringUtils.equals(c.getUsrcrtvalLm(), "NBSZIBB") || StringUtils.equals(c.getUsrcrtvalLm(), "PCC___Z") || StringUtils.equals(c.getUsrcrtvalLm(), "REBATCH") || StringUtils.equals(c.getUsrcrtvalLm(), "NBS3A_Z") || StringUtils.equals(c.getUsrcrtvalLm(), "04CDCRZ") || StringUtils.equals(c.getUsrcrtvalLm(), "04CDMOZ") || StringUtils.equals(c.getUsrcrtvalLm(), "04C_MIS")))  && IntegerUtils.equals(c.getSsdCf(), 17) && (StringUtils.equals(c.getNatCf(), "10") || StringUtils.equals(c.getNatCf(), "11") || StringUtils.equals(c.getNatCf(), "12") || StringUtils.equals(c.getNatCf(), "20") || StringUtils.equals(c.getNatCf(), "21") || StringUtils.equals(c.getNatCf(), "22") || StringUtils.equals(c.getNatCf(), "23")) && StringUtils.equals(c.getTflInd(), "T") && (IntegerUtils.equals(c.getSecstsCt(), 14) || IntegerUtils.equals(c.getSecstsCt(), 16) || IntegerUtils.equals(c.getSecstsCt(), 17) || IntegerUtils.equals(c.getSecstsCt(), 19)) && !((IntegerUtils.equals(c.getCedNf(), 11508) || IntegerUtils.equals(c.getCedNf(), 11550) || IntegerUtils.equals(c.getCedNf(), 11564) || IntegerUtils.equals(c.getCedNf(), 11721) || IntegerUtils.equals(c.getCedNf(), 11761) || IntegerUtils.equals(c.getCedNf(), 12365) || IntegerUtils.equals(c.getCedNf(), 12492) || IntegerUtils.equals(c.getCedNf(), 12726) || IntegerUtils.equals(c.getCedNf(), 12748)))  && !((IntegerUtils.equals(c.getAccadmtypCt(), 1) || IntegerUtils.equals(c.getAccadmtypCt(), 4)))  && ((StringUtils.equals(c.getLobCf(), "05") && (StringUtils.equals(c.getTopCf(), "130") || StringUtils.equals(c.getTopCf(), "131") || StringUtils.equals(c.getTopCf(), "137") || StringUtils.equals(c.getTopCf(), "138") || StringUtils.equals(c.getTopCf(), "170") || StringUtils.equals(c.getTopCf(), "190") || StringUtils.equals(c.getTopCf(), "195")))) && !(IntegerUtils.superiorOrEquals(c.getClissdCf(), 1))  && !BooleanUtils.equals(c.getTrftrtB(), true)', getDate(), 'DBEU', getDate(), 'MICM', null )
insert into TSEGMENTRULE (SGTRUL_NT, SGMT_NF, SGT_NT, SGTVER_NT, RULE_LS, RULPRIO_CT, FUNCDEF_T, TECHDEF_T, CRE_D, CREUSR_CF, LSTUPD_D, LSTUPDUSR_CF, timestamp) values (1,100,1220,1,'',91,' UW_PFT_ORIGIN = 255 AND SEC_NATURE In (''10'',''11'',''12'',''20'',''21'',''22'',''23'') AND TTY_FAC_LIFE = ''T'' AND SEC_STATUS In (14,16,17,19) AND not(CLIENT_SCOR >= 1) AND CTR_TRANSFERED <> true','IntegerUtils.equals(c.getUworgCf(), 255) && (StringUtils.equals(c.getNatCf(), "10") || StringUtils.equals(c.getNatCf(), "11") || StringUtils.equals(c.getNatCf(), "12") || StringUtils.equals(c.getNatCf(), "20") || StringUtils.equals(c.getNatCf(), "21") || StringUtils.equals(c.getNatCf(), "22") || StringUtils.equals(c.getNatCf(), "23")) && StringUtils.equals(c.getTflInd(), "T") && (IntegerUtils.equals(c.getSecstsCt(), 14) || IntegerUtils.equals(c.getSecstsCt(), 16) || IntegerUtils.equals(c.getSecstsCt(), 17) || IntegerUtils.equals(c.getSecstsCt(), 19)) && !(IntegerUtils.superiorOrEquals(c.getClissdCf(), 1))  && !BooleanUtils.equals(c.getTrftrtB(), true)',getDate(),'DBEU',getDate(),'DBEU',null)
